let amountProgressMR=0;function calculateTimeInterval(){const e=new Date,t=new Date(e);t.setHours(0,0,0,0);const n=new Date(t);return n.setHours(24,0,0,0),{from:t.toISOString(),to:n.toISOString()}}function buildAllProgressBars(e,t){e.forEach((e=>{const n=document.getElementById(e.parentId);n?buildProgressBar(e,n,t):console.warn(`Parent with id ${e.parentId} not found.`)}))}function calculatePercent(e,t,n){const r=t-e;if(0===r)return 0;const o=(n-e)/r*100;return o>100?100:o<0?0:o}function buildProgressBar(e,t,n){const r=calculatePercent(e.range.start,e.range.end,n),o=e.progress.map((e=>{const t=e.text.toLowerCase().replace(/[^a-z0-9_-]/g,"");return`<div class="current_progress ${r>e.percent?`open-present-${t} progress-achieved`:`present-${t}`}" style="position: absolute; left: ${e.percent}%; transform: translateX(-50%);">${e.text}</div>`})).join("");let s="",a="position: absolute; left: 0;";0===r?s="hidden":r>0&&r<2?s="min-width":r>90?(s="full-radius",a+=`width: ${r}%;`):a+=`width: ${r}%;`;const i=`\n                <div style="display: flex; width: 100%; justify-content: center;">\n                    <div class="progressbarInfo" style="position: relative;">${e.range.start}₾ - ${e.range.end}₾</div>\n                </div>\n                <div class="progressbar progress-${e.range.end}" style="position: relative; width: 100%;">\n                    <div class="activeProgress ${s}" style="${a}"></div>\n                    ${o}\n                </div>\n            `;t.innerHTML=i;t.querySelector(".progressbar");const c=e.range.start,d=e.range.end,l=`progressbar-style-${Date.now()}`,u=document.createElement("style");u.id=l,document.head.appendChild(u),u.textContent=`\n                .progress-${e.range.end}::before {\n                    content: "${c}";\n                    position: absolute;\n                    top: 50%;\n                    transform: translateY(-50%);\n                    font-size: 10px;\n                    z-index: 4;\n                    left: 10px;\n                    color: #000;\n                }\n                .progress-${e.range.end}::after {\n                    content: "${d}";\n                    position: absolute;\n                    top: 50%;\n                    z-index: 4;\n                    transform: translateY(-50%);\n                    font-size: 10px;\n                    right: 10px;\n                    color: #000;\n                }\n            `}async function showProgressBarMrch(){const e=calculateTimeInterval(),t=extractAuthDataFromCookie();if(!t)return 0;try{const n=await fetchGraphQL("\n                query GameSessionStats($userId: ID!, $createdAtFrom: DateTime, $createdAtTo: DateTime) {\n                    gameSessionStats(userId: $userId, createdAtFrom: $createdAtFrom, createdAtTo: $createdAtTo) {\n                        totalBet\n                    }\n                }\n            ",{userId:t.userId,createdAtFrom:e.from,createdAtTo:e.to});return n.data?.gameSessionStats?.[0]?.totalBet||0}catch(e){return console.error("Error fetching progress data:",e),0}}